    fn set_preview_layout(&mut self, mode: PreviewLayoutMode) {
        self.preview_layout = mode;
        self.last_action = match mode {
            PreviewLayoutMode::Chat => "chat view".to_string(),
            PreviewLayoutMode::Graph => "graph view".to_string(),
        };
    }

    fn begin_surface_request(
        &mut self,
        request_meta: YggRequestMeta,
        label: String,
        global_busy: bool,
    ) {
        let request_id = request_meta.request_id.clone();
        let request_surface = request_meta.surface;
        let request_operation = request_meta.operation.clone();
        let request_target = request_meta.target.clone();
        if request_meta.priority == YggOperationPriority::Interactive {
            self.background_refresh_after_ms = self
                .background_refresh_after_ms
                .max(current_millis() + BACKGROUND_REFRESH_INTERACTIVE_DEFER_MS);
        }
        if let Ok(store) = SessionStore::open_or_init() {
            append_trace_event(
                store.home_dir(),
                "ui",
                "surface_request",
                "begin",
                json!({
                    "request_id": request_meta.request_id.clone(),
                    "operation": request_meta.operation.clone(),
                    "surface": format!("{:?}", request_meta.surface),
                    "target": request_meta.target.clone(),
                    "global_busy": global_busy,
                    "label": label.clone(),
                }),
            );
        }
        if global_busy {
            self.busy_request_id = Some(request_meta.request_id.clone());
            self.server_busy = true;
        }
        if matches!(request_surface, YggSurface::Preview | YggSurface::Terminal) {
            let conflicting_surface = match request_surface {
                YggSurface::Preview => Some(YggSurface::Terminal),
                YggSurface::Terminal => Some(YggSurface::Preview),
                _ => None,
            };
            if let Some(conflicting_surface) = conflicting_surface {
                if let Some(conflicting_request) =
                    self.active_surface_requests.remove(&conflicting_surface)
                {
                    self.clear_job_notification(&format!("loading:{}", conflicting_request.request_id));
                    if let Ok(store) = SessionStore::open_or_init() {
                        append_trace_event(
                            store.home_dir(),
                            "ui",
                            "surface_request",
                            "cleared_conflict",
                            json!({
                                "request_id": conflicting_request.request_id,
                                "conflicting_surface": format!("{conflicting_surface:?}"),
                                "replacement_request_id": request_id,
                                "replacement_surface": format!("{request_surface:?}"),
                                "replacement_operation": request_operation,
                                "replacement_target": serde_json::to_value(&request_target).unwrap_or(Value::Null),
                            }),
                        );
                    }
                }
            }
        }
        let replaced = self.active_surface_requests.insert(
            request_surface,
            ActiveSurfaceRequest {
                request_id: request_meta.request_id,
                operation: request_meta.operation,
                target: request_meta.target,
            },
        );
        if let Some(replaced) = replaced
            && replaced.request_id != request_id
        {
            self.clear_job_notification(&format!("loading:{}", replaced.request_id));
            if let Ok(store) = SessionStore::open_or_init() {
                append_trace_event(
                    store.home_dir(),
                    "ui",
                    "surface_request",
                    "superseded",
                    json!({
                        "request_id": replaced.request_id,
                        "replacement_request_id": request_id,
                        "surface": format!("{request_surface:?}"),
                        "replacement_operation": request_operation,
                        "replacement_target": serde_json::to_value(&request_target).unwrap_or(Value::Null),
                    }),
                );
            }
        }
        self.last_action = label;
    }

    fn begin_busy_request(&mut self, request_meta: YggRequestMeta, label: String) {
        self.begin_surface_request(request_meta, label, true);
    }

    fn finish_busy_request_for(&mut self, request_id: &str) {
        if let Ok(store) = SessionStore::open_or_init() {
            append_trace_event(
                store.home_dir(),
                "ui",
                "surface_request",
                "end",
                json!({ "request_id": request_id }),
            );
        }
        if self.busy_request_id.as_deref() == Some(request_id) {
            self.busy_request_id = None;
        }
        self.clear_job_notification(&format!("loading:{request_id}"));
        self.active_surface_requests
            .retain(|_, request| request.request_id != request_id);
        if self.active_surface_requests.is_empty() {
            self.server_busy = false;
        }
    }

    fn apply_daemon_snapshot_result(&mut self, result: Result<(ServerUiSnapshot, Option<String>)>) {
        let request_id = self.busy_request_id.clone();
        if let Some(request_id) = request_id.as_deref() {
            self.apply_daemon_snapshot_result_for(request_id, result);
            return;
        }
        let was_initial_sync = self.needs_initial_server_sync;
        let previous_active_session = self.server.active_session().cloned();
        match result {
            Ok((mut snapshot, message)) => {
                preserve_client_focus_for_background_snapshot(self, &mut snapshot);
                self.server.apply_snapshot(snapshot);
                self.restore_active_preview_if_snapshot_regressed(previous_active_session);
                self.mark_active_remote_preview_dirty_if_needed();
                self.prune_terminal_attach_in_flight();
                self.prune_terminal_resume_ready_paths();
                self.hydrate_generated_copy_from_remote_cache();
                self.needs_initial_server_sync = false;
                self.next_background_copy_scan_after_ms = 0;
                if was_initial_sync {
                    self.seed_dynamic_top_level_expansions();
                }
                self.ensure_active_session_expanded();
                if was_initial_sync || self.selected_tree_paths.is_empty() {
                    self.sync_active_session_selection();
                }
                self.sync_browser_settings();
                self.refresh_search_state("apply_daemon_snapshot_result");
                self.record_restore_issue_telemetry("apply_daemon_snapshot_result");
                self.record_preview_issue_telemetry("apply_daemon_snapshot_result");
                if let Some(message) = message {
                    self.last_action = message;
                }
            }
            Err(error) => {
                self.needs_initial_server_sync = false;
                self.next_background_copy_scan_after_ms = current_millis() + 2_000;
                self.last_action = format!("server sync failed: {error}");
                if !self.had_cached_startup_snapshot {
                    self.push_notification(
                        NotificationTone::Error,
                        "Server Sync Failed",
                        error.to_string(),
                    );
                }
            }
        }
    }

    fn apply_daemon_snapshot_result_for(
        &mut self,
        request_id: &str,
        result: Result<(ServerUiSnapshot, Option<String>)>,
    ) {
        let was_initial_sync = self.needs_initial_server_sync;
        let previous_active_session = self.server.active_session().cloned();
        match result {
            Ok((snapshot, message)) => {
                let snapshot = self.reconcile_snapshot_for_request(request_id, snapshot);
                self.server.apply_snapshot(snapshot);
                self.restore_active_preview_if_snapshot_regressed(previous_active_session);
                self.mark_active_remote_preview_dirty_if_needed();
                self.prune_terminal_attach_in_flight();
                self.prune_terminal_resume_ready_paths();
                self.hydrate_generated_copy_from_remote_cache();
                self.finish_busy_request_for(request_id);
                self.needs_initial_server_sync = false;
                self.next_background_copy_scan_after_ms = 0;
                if was_initial_sync {
                    self.seed_dynamic_top_level_expansions();
                }
                self.ensure_active_session_visible();
                self.record_restore_issue_telemetry("apply_daemon_snapshot_result");
                self.record_preview_issue_telemetry("apply_daemon_snapshot_result");
                if let Some(message) = message {
                    self.last_action = message;
                }
            }
            Err(error) => {
                self.finish_busy_request_for(request_id);
                self.needs_initial_server_sync = false;
                self.next_background_copy_scan_after_ms = current_millis() + 2_000;
                self.last_action = format!("server sync failed: {error}");
                if !self.had_cached_startup_snapshot {
                    self.push_notification(
                        NotificationTone::Error,
                        "Server Sync Failed",
                        error.to_string(),
                    );
                }
            }
        }
    }

    fn restore_active_preview_if_snapshot_regressed(
        &mut self,
        previous_active_session: Option<ManagedSessionView>,
    ) {
        let Some(previous_active_session) = previous_active_session else {
            return;
        };
        if self.server.active_view_mode() != WorkspaceViewMode::Rendered {
            return;
        }
        if previous_active_session.preview.blocks.is_empty() {
            return;
        }
        let Some(active_path) = self.server.active_session_path().map(str::to_string) else {
            return;
        };
        if active_path != previous_active_session.session_path {
            return;
        }
        let _ = self.server.restore_session_preview_if_empty(
            &active_path,
            previous_active_session.preview,
            previous_active_session.rendered_sections,
        );
    }

    fn mark_active_remote_preview_dirty_if_needed(&mut self) {
        if self.server.active_view_mode() != WorkspaceViewMode::Rendered {
            return;
        }
        let Some(session) = self.server.active_session().cloned() else {
            return;
        };
        if !session.session_path.starts_with("remote-session://") {
            return;
        }
        if !remote_preview_needs_refresh(&session) {
            return;
        }
        self.remote_preview_dirty_epoch
            .insert(session.session_path, current_millis());
    }

    fn seed_dynamic_top_level_expansions(&mut self) {
        let mut paths = self
            .server
            .remote_machines()
            .iter()
            .map(|machine| format!("__remote_machine__/{}", machine.machine_key))
            .collect::<Vec<_>>();
        if self
            .server
            .live_sessions()
            .iter()
            .any(|session| session.kind != SessionKind::SshShell)
        {
            paths.push("__live_sessions__".to_string());
        }
        self.browser.ensure_expanded_paths(paths);
        self.sync_browser_settings();
    }

    fn ensure_active_session_visible(&mut self) {
        self.ensure_active_session_expanded();
        self.sync_active_session_selection();
        self.sync_browser_settings();
    }

    fn prune_terminal_attach_in_flight(&mut self) {
        if self.server.active_view_mode() != WorkspaceViewMode::Terminal {
            self.terminal_attach_in_flight.clear();
            return;
        }
        let Some(active_path) = self.server.active_session_path().map(str::to_owned) else {
            self.terminal_attach_in_flight.clear();
            return;
        };
        self.terminal_attach_in_flight
            .retain(|session_path| session_path == &active_path);
    }

    fn prune_terminal_resume_ready_paths(&mut self) {
        if self.server.active_view_mode() != WorkspaceViewMode::Terminal {
            self.terminal_resume_ready_paths.clear();
            return;
        }
        let Some(active_path) = self.server.active_session_path().map(str::to_owned) else {
            self.terminal_resume_ready_paths.clear();
            return;
        };
        self.terminal_resume_ready_paths
            .retain(|session_path| session_path == &active_path);
    }

    fn ensure_active_session_expanded(&mut self) {
        let remote_paths = self.active_session_visibility_paths();
        if !remote_paths.is_empty() {
            self.browser.ensure_expanded_paths(remote_paths);
        } else if let Some(active_path) = self.active_browser_selection_path_for_session() {
            self.browser.ensure_visible_path(&active_path);
        }
    }

    fn sync_active_session_selection(&mut self) {
        if let Some(active) = self.server.active_session().cloned() {
            let selected_path = self
                .active_browser_selection_path_for_session()
                .unwrap_or_else(|| active.session_path.clone());
            self.selected_tree_paths.clear();
            self.selected_tree_paths.insert(selected_path.clone());
            self.selection_anchor = Some(selected_path.clone());
            self.browser.select_path(selected_path);
        }
    }

    fn active_browser_selection_path_for_session(&self) -> Option<String> {
        let active = self.server.active_session()?;
        let active_path = active.session_path.clone();
        if self
            .browser
            .rows()
            .iter()
            .any(|row| row.full_path == active_path)
        {
            return Some(active_path);
        }
        self.browser.rows().iter().find_map(|row| {
            (row.session_id.as_deref() == Some(active.id.as_str())
                && matches!(row.kind, BrowserRowKind::Session | BrowserRowKind::Document))
            .then(|| row.full_path.clone())
        })
    }

    fn active_session_visibility_paths(&self) -> Vec<String> {
        let active_path = self
            .server
            .active_session()
            .map(|session| session.session_path.clone())
            .or_else(|| self.server.active_session_path().map(ToOwned::to_owned));
        let Some(active_path) = active_path else {
            return Vec::new();
        };
        if self
            .server
            .live_sessions()
            .iter()
            .any(|session| session.session_path == active_path && is_promoted_live_session(session))
        {
            let mut paths = vec!["__live_sessions__".to_string()];
            if let Some((machine_key, _session_id)) =
                parse_remote_scanned_session_path(&active_path)
            {
                paths.push(format!("__remote_machine__/{machine_key}"));
                let active_cwd = self
                    .server
                    .active_session()
                    .map(|active| metadata_value(active, "Cwd"))
                    .unwrap_or_default();
                if let Some(machine) = self
                    .server
                    .remote_machines()
                    .iter()
                    .find(|machine| machine.machine_key == machine_key)
                    && !active_cwd.trim().is_empty()
                {
                    paths.extend(
                        compressed_remote_folder_paths(&machine.sessions, &active_cwd)
                            .into_iter()
                            .map(|path| format!("__remote_folder__/{machine_key}{path}")),
                    );
                }
            }
            return paths;
        }
        let Some((machine_key, session_id)) = parse_remote_scanned_session_path(&active_path)
        else {
            return Vec::new();
        };
        let mut paths = vec![format!("__remote_machine__/{machine_key}")];
        let active_cwd = self
            .server
            .active_session()
            .map(|active| metadata_value(active, "Cwd"));
        if let Some(machine) = self
            .server
            .remote_machines()
            .iter()
            .find(|machine| machine.machine_key == machine_key)
        {
            let cwd = active_cwd.unwrap_or_else(|| {
                machine
                    .sessions
                    .iter()
                    .find(|session| {
                        session.session_path == active_path || session.session_id == session_id
                    })
                    .map(|session| session.cwd.clone())
                    .unwrap_or_default()
            });
            paths.extend(
                compressed_remote_folder_paths(&machine.sessions, &cwd)
                    .into_iter()
                    .map(|path| format!("__remote_folder__/{machine_key}{path}")),
            );
        } else {
            let cwd = active_cwd.unwrap_or_default();
            let mut current = String::new();
            for segment in cwd.split('/').filter(|segment| !segment.is_empty()) {
                current.push('/');
                current.push_str(segment);
                paths.push(format!("__remote_folder__/{machine_key}{current}"));
            }
        }
        paths
    }

    fn hydrate_generated_copy_from_remote_cache(&mut self) {
        let cached = self
            .server
            .remote_machines()
            .iter()
            .flat_map(|machine| machine.sessions.iter())
            .map(|session| {
                (
                    session.session_path.clone(),
                    session.title_hint.clone(),
                    session.cached_precis.clone(),
                    session.cached_summary.clone(),
                )
            })
            .collect::<Vec<_>>();
        for (session_path, title_hint, precis, summary) in cached {
            if !title_hint.trim().is_empty() && !looks_like_generated_fallback_title(&title_hint) {
                self.server
                    .set_session_title_hint(&session_path, &title_hint);
            }
            if let Some(precis) = precis {
                self.generated_precis
                    .insert(session_path.clone(), precis.clone());
                self.server.set_session_precis_hint(&session_path, &precis);
            }
            if let Some(summary) = summary {
                self.generated_summaries
                    .insert(session_path.clone(), summary.clone());
                self.server
                    .set_session_summary_hint(&session_path, &summary);
            }
        }
    }

    fn select_row(&mut self, row: &BrowserRow) {
        self.browser.select_path(row.full_path.clone());
        self.record_ui_telemetry(
            "tree_activate",
            json!({
                "path": row.full_path,
                "kind": format!("{:?}", row.kind),
                "selected_paths": self.selected_tree_paths.iter().cloned().collect::<Vec<_>>(),
            }),
        );
        match row.kind {
            BrowserRowKind::Group => {
                if is_synthetic_sidebar_row(row) {
                    self.browser.toggle_virtual_group(&row.full_path);
                } else {
                    self.browser.toggle_group(&row.full_path);
                }
                self.suppress_tree_click_until_ms = current_millis().saturating_add(220);
                self.sync_browser_settings();
                self.last_action = format!("toggled {}", row.label);
            }
            BrowserRowKind::Separator => {
                self.context_menu_row = None;
                self.last_action = format!("selected {}", row.label);
            }
            BrowserRowKind::Session | BrowserRowKind::Document => {
                self.context_menu_row = None;
                self.apply_daemon_snapshot_result(open_stored_session(
                    &self.bootstrap.server_endpoint,
                    session_kind_for_row(row.kind),
                    &row.full_path,
                    row.session_id.as_deref(),
                    row.session_cwd.as_deref(),
                    Some(row.label.as_str()),
                ));
                self.sync_browser_settings();
                self.last_action = format!("opened {}", row.label);
            }
        }
    }

