#[component]
fn MainSurface(
    state: Signal<ShellState>,
    snapshot: SharedSnapshot,
    terminal_mount_epoch: u64,
    on_expand_preview: EventHandler<()>,
    on_collapse_preview: EventHandler<()>,
    on_toggle_preview_block: EventHandler<usize>,
    on_set_preview_layout: EventHandler<PreviewLayoutMode>,
    on_save_document: EventHandler<(String, WorkspaceDocumentInput)>,
    on_run_recipe_document: EventHandler<(String, WorkspaceDocumentInput, bool)>,
) -> Element {
    let active_session_path = snapshot.active_session_path.clone();
    let surface_view_key = match snapshot.active_view_mode {
        WorkspaceViewMode::Rendered => "preview",
        WorkspaceViewMode::Terminal => "terminal",
    };
    let surface_key = format!(
        "{}:{surface_view_key}:{terminal_mount_epoch}",
        active_session_path
            .clone()
            .unwrap_or_else(|| "__empty__".to_string())
    );
    let mut preview_scroll_top = use_signal(|| 0.0_f64);
    let mut preview_scroll_client_height = use_signal(|| PREVIEW_MIN_VIEWPORT_HEIGHT_PX);
    let mut preview_scroll_height = use_signal(|| PREVIEW_MIN_VIEWPORT_HEIGHT_PX);
    let mut preview_reset_key = use_signal(String::new);
    let preview_reset_session_path = active_session_path.clone();
    let preview_reset_view_mode = snapshot.active_view_mode as u8;
    use_effect(move || {
        let reset_key = format!(
            "{}:{}",
            preview_reset_session_path
                .clone()
                .unwrap_or_else(|| "__empty__".to_string()),
            preview_reset_view_mode
        );
        if *preview_reset_key.read() == reset_key {
            return;
        }
        preview_reset_key.set(reset_key);
        preview_scroll_top.set(0.0);
        preview_scroll_client_height.set(PREVIEW_MIN_VIEWPORT_HEIGHT_PX);
        preview_scroll_height.set(PREVIEW_MIN_VIEWPORT_HEIGHT_PX);
    });
    let render_trace_session_path = active_session_path.clone();
    let render_trace_surface_key = surface_key.clone();
    let render_trace_view_mode = snapshot.active_view_mode;
    let render_trace_session_kind = snapshot
        .active_session
        .as_ref()
        .map(|session| format!("{:?}", session.kind));
    use_effect(move || {
        let trace_home = perf_home_dir(&state.read().bootstrap.settings_path);
        append_trace_event(
            &trace_home,
            "ui",
            "main_surface",
            "render",
            json!({
                "surface_key": render_trace_surface_key,
                "active_view_mode": format!("{:?}", render_trace_view_mode),
                "active_session_path": render_trace_session_path,
            }),
        );
        if render_trace_view_mode == WorkspaceViewMode::Rendered {
            append_trace_event(
                &trace_home,
                "ui",
                "main_surface",
                "viewport_ready",
                json!({
                    "surface_key": render_trace_surface_key,
                    "active_view_mode": format!("{:?}", render_trace_view_mode),
                    "active_session_path": render_trace_session_path,
                    "session_kind": render_trace_session_kind,
                }),
            );
        }
    });
    let rendered_surface_zoom_percent =
        zoom_percent_f32(snapshot.settings.terminal_font_size, 10.0);
    let rendered_surface_zoom_style = format!(
        "display:flex; flex-direction:column; min-width:0; min-height:0; width:100%; height:100%; zoom:{}%;",
        rendered_surface_zoom_percent
    );
    let body = if let Some(session) = snapshot.active_session.clone() {
        match snapshot.active_view_mode {
            WorkspaceViewMode::Rendered => {
                if session.kind == SessionKind::Document {
                    rsx! {
                        div {
                            style: "{rendered_surface_zoom_style}",
                            DocumentEditor {
                                key: "{session.session_path}",
                                session: session.clone(),
                                palette: snapshot.palette,
                                server_busy: snapshot.server_busy,
                                on_save: on_save_document,
                                on_run_recipe_document,
                            }
                        }
                    }
                } else {
                    let visible_blocks = visible_preview_blocks(&session);
                    let rendered_sections = preview_rendered_sections(&session);
                    let preview_failure = snapshot.preview_failure.clone();
                    let preview_window = preview_virtual_window(
                        &visible_blocks,
                        *preview_scroll_top.read(),
                        *preview_scroll_client_height.read(),
                        *preview_scroll_height.read(),
                        snapshot.search_active,
                    );
                    let rendered_blocks = visible_blocks
                        [preview_window.start_index..preview_window.end_index]
                        .to_vec();
                    let grouped_runs =
                        group_preview_runs(&rendered_blocks, preview_window.start_index);
                    let show_failure_placeholder = preview_failure.is_some()
                        && grouped_runs.is_empty()
                        && rendered_sections.is_empty();
                    let show_loading_placeholder = !show_failure_placeholder
                        && snapshot.preview_loading
                        && grouped_runs.is_empty()
                        && rendered_sections.is_empty();
                    rsx! {
                        div {
                            key: "{session.session_path}:{snapshot.active_view_mode as u8}",
                            style: "{rendered_surface_zoom_style}",
                            div {
                                style: "display:flex; align-items:flex-start; justify-content:flex-end; gap:12px; padding:8px 24px 0 24px;",
                                PreviewToolbar {
                                    palette: snapshot.palette,
                                    preview_layout: snapshot.preview_layout,
                                    preview_loading: snapshot.preview_loading,
                                    server_busy: snapshot.server_busy,
                                    on_expand_preview: move |_| on_expand_preview.call(()),
                                    on_collapse_preview: move |_| on_collapse_preview.call(()),
                                    on_set_preview_layout: move |mode| on_set_preview_layout.call(mode),
                                }
                            }
                            div {
                                key: "{session.session_path}:preview-scroll",
                                "data-preview-scroll": "1",
                                "data-preview-scroll-active": "true",
                                "data-preview-session-path": "{session.session_path}",
                                style: "display:flex; flex-direction:column; gap:14px; min-width:0; min-height:0; overflow:auto; padding:8px 24px 24px 24px; \
                                        overscroll-behavior:contain; scrollbar-gutter:stable;",
                                onscroll: move |evt: ScrollEvent| {
                                    preview_scroll_top.set(evt.data().scroll_top());
                                    preview_scroll_client_height
                                        .set((evt.data().client_height() as f64).max(PREVIEW_MIN_VIEWPORT_HEIGHT_PX));
                                    preview_scroll_height
                                        .set((evt.data().scroll_height() as f64).max(PREVIEW_MIN_VIEWPORT_HEIGHT_PX));
                                },
                                if snapshot.preview_layout == PreviewLayoutMode::Chat {
                                    div {
                                        "data-preview-window-start": "{preview_window.start_index}",
                                        "data-preview-window-end": "{preview_window.end_index}",
                                        "data-preview-session-path": "{session.session_path}",
                                        "data-preview-window-total": "{visible_blocks.len()}",
                                        "data-preview-window-top-spacer": "{preview_window.top_spacer_px.round() as i64}",
                                        "data-preview-window-bottom-spacer": "{preview_window.bottom_spacer_px.round() as i64}",
                                        "data-preview-window-total-height": "{preview_window.total_height_px.round() as i64}",
                                        "data-preview-window-scroll-top": "{preview_window.scroll_top_px.round() as i64}",
                                        "data-preview-window-client-height": "{preview_window.viewport_height_px.round() as i64}",
                                        "data-preview-window-scroll-height": "{preview_window.scroll_height_px.round() as i64}",
                                        "data-preview-window-overscan": "{preview_window.overscan_px.round() as i64}",
                                        style: "display:flex; flex-direction:column; gap:14px; min-width:0; width:min(1020px, 100%); margin:0 auto;",
                                        if !rendered_sections.is_empty() {
                                            RenderedSectionsStrip {
                                                sections: rendered_sections.clone(),
                                                palette: snapshot.palette,
                                            }
                                        }
                                        if show_loading_placeholder {
                                            PreviewLoadingPlaceholder {
                                                session: session.clone(),
                                                palette: snapshot.palette,
                                            }
                                        }
                                        if let Some(message) = preview_failure.clone().filter(|_| show_failure_placeholder) {
                                            PreviewFailurePlaceholder {
                                                session: session.clone(),
                                                palette: snapshot.palette,
                                                message,
                                            }
                                        }
                                        if preview_window.top_spacer_px > 0.0 {
                                            div {
                                                "data-preview-spacer": "top",
                                                style: format!("height:{}px; min-height:{}px;", preview_window.top_spacer_px.round(), preview_window.top_spacer_px.round()),
                                            }
                                        }
                                        for run in grouped_runs.into_iter() {
                                            PreviewRunBlock {
                                                session_id: session.id.clone(),
                                                run: run.clone(),
                                                palette: snapshot.palette,
                                                on_toggle_block: move |ix| on_toggle_preview_block.call(ix),
                                            }
                                        }
                                        if preview_window.bottom_spacer_px > 0.0 {
                                            div {
                                                "data-preview-spacer": "bottom",
                                                style: format!("height:{}px; min-height:{}px;", preview_window.bottom_spacer_px.round(), preview_window.bottom_spacer_px.round()),
                                            }
                                        }
                                    }
                                } else {
                                    div {
                                        style: "width:min(1120px, 100%); margin:0 auto;",
                                        PreviewGraph {
                                            session: session.clone(),
                                            visible_blocks: visible_blocks.clone(),
                                            rendered_sections: rendered_sections.clone(),
                                            palette: snapshot.palette,
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
            WorkspaceViewMode::Terminal => rsx! {
                div {
                    key: "{session.session_path}:{snapshot.settings.terminal_font_size}:{snapshot.active_view_mode as u8}:{terminal_mount_epoch}",
                    style: "display:flex; flex-direction:column; min-width:0; min-height:0; width:100%; height:100%;",
                    TerminalCanvas {
                        key: "{terminal_instance_key(&session.session_path, snapshot.settings.terminal_font_size)}:{terminal_mount_epoch}",
                        session: session.clone(),
                        snapshot: snapshot.clone(),
                        state,
                        mount_epoch: terminal_mount_epoch,
                    }
                }
            },
        }
    } else {
        rsx! {
            EmptyState { palette: snapshot.palette }
        }
    };

    rsx! {
        div {
            key: "{surface_key}",
            style: format!(
                "flex:1; min-width:0; min-height:0; display:flex; flex-direction:column; background:transparent; padding:{};",
                if snapshot.fullscreen { "0" } else { "12px 12px 10px 0" }
            ),
            div {
                key: "{surface_key}-body",
                style: format!(
                    "flex:1; min-height:0; overflow:{}; padding:{}; background:{}; border-radius:{}; box-shadow:{};",
                    if snapshot.active_view_mode == WorkspaceViewMode::Terminal { "hidden" } else { "auto" },
                    if snapshot.active_view_mode == WorkspaceViewMode::Terminal { "0" } else { "24px" },
                    if snapshot.active_view_mode == WorkspaceViewMode::Terminal {
                        "transparent"
                    } else {
                        snapshot.palette.panel
                    },
                    if snapshot.fullscreen { "0" } else { "11px" },
                    if snapshot.active_view_mode == WorkspaceViewMode::Terminal {
                        "none"
                    } else {
                        snapshot.palette.panel_shadow
                    }
                ),
                {body}
            }
        }
    }
}

#[component]
fn SessionHeaderCopy(
    title: String,
    subtitle: String,
    allow_subtitle_scroll: bool,
    palette: Palette,
    loading_label: Option<String>,
    on_refresh_title: EventHandler<MouseEvent>,
    on_refresh_subtitle: EventHandler<MouseEvent>,
) -> Element {
    let subtitle_style = if allow_subtitle_scroll {
        format!(
            "font-size:12px; line-height:1.72; color:{}; white-space:pre-wrap; overflow-wrap:anywhere; min-width:0; flex:1; max-height:40vh; overflow:auto; padding-right:6px; scrollbar-gutter:stable;",
            palette.muted
        )
    } else {
        format!(
            "font-size:12px; line-height:1.72; color:{}; white-space:pre-wrap; overflow-wrap:anywhere; min-width:0; flex:1; max-height:none; overflow:visible; padding-right:6px;",
            palette.muted
        )
    };
    rsx! {
        div {
            style: "display:flex; flex-direction:column; gap:10px; min-width:280px; flex:1; min-height:0;",
            div {
                style: "display:flex; align-items:flex-start; justify-content:space-between; gap:12px;",
                div {
                    style: "display:flex; flex-direction:column; gap:4px; min-width:0;",
                    div {
                        style: "display:flex; align-items:center; gap:8px; min-width:0;",
                        div {
                            style: format!("font-size:22px; font-weight:700; color:{}; line-height:1.2; min-width:0;", palette.text),
                            "{title}"
                        }
                        if let Some(loading_label) = loading_label.clone() {
                            LoadingStateChip {
                                label: loading_label,
                                palette,
                            }
                        }
                        RefreshInlineButton {
                            label: "Regenerate title".to_string(),
                            palette,
                            onclick: move |evt| on_refresh_title.call(evt),
                        }
                    }
                }
            }
            div {
                style: "display:flex; align-items:flex-start; gap:8px; min-width:0; min-height:0;",
                div {
                    style: "{subtitle_style}",
                    "{subtitle}"
                }
                RefreshInlineButton {
                    label: "Regenerate detail".to_string(),
                    palette,
                    onclick: move |evt| on_refresh_subtitle.call(evt),
                }
            }
        }
    }
}

