#[component]
fn RenderedSectionCard(section: SessionRenderedSection, palette: Palette) -> Element {
    let is_commands = section.title.to_ascii_lowercase().contains("command");
    let is_goals = section.title.to_ascii_lowercase().contains("goal");
    let visible_lines = section.lines.iter().take(3).cloned().collect::<Vec<_>>();
    let visible_count = visible_lines.len();
    rsx! {
        div {
            "data-preview-rendered-section": "1",
            "data-preview-rendered-section-title": "{section.title}",
            style: format!(
                "display:flex; flex-direction:column; gap:10px; min-width:0; padding:14px 16px; border-radius:18px; \
                 background:{}; box-shadow:inset 0 0 0 1px {};"
                ,
                if is_goals { "rgba(236,248,247,0.92)" } else { "rgba(255,255,255,0.82)" },
                if is_goals { "rgba(74,163,153,0.16)" } else { "rgba(170,190,212,0.14)" }
            ),
            div {
                style: "display:flex; align-items:center; justify-content:space-between; gap:12px;",
                div {
                    style: format!("font-size:12px; font-weight:700; letter-spacing:0.03em; text-transform:uppercase; color:{};", if is_goals { "#2c8c83" } else { palette.muted }),
                    "{section.title}"
                }
                if section.lines.len() > visible_count {
                    div {
                        style: format!("font-size:11px; color:{};", palette.muted),
                        "{section.lines.len()} lines"
                    }
                }
            }
            div {
                style: "display:flex; flex-direction:column; gap:8px; min-width:0;",
                for line in visible_lines {
                    if is_commands {
                        div {
                            style: format!(
                                "font-size:12px; line-height:1.6; white-space:pre-wrap; font-family:'JetBrains Mono', 'Iosevka Term', monospace; \
                                 color:{}; padding:8px 10px; border-radius:12px; background:rgba(15,23,42,0.06); overflow-wrap:anywhere;",
                                palette.text
                            ),
                            "{line}"
                        }
                    } else {
                        div {
                            "data-preview-rendered-line": "1",
                            style: format!("font-size:13px; line-height:1.62; white-space:pre-wrap; color:{};", palette.text),
                            "{line}"
                        }
                    }
                }
                if section.lines.len() > visible_count {
                    div {
                        style: format!("font-size:11px; font-weight:600; color:{};", palette.muted),
                        "+ {section.lines.len() - visible_count} more"
                    }
                }
            }
        }
    }
}

fn preview_summary_text(session: &ManagedSessionView) -> String {
    if let Some(summary) = preview_summary_metadata_value(session, "Summary")
        .filter(|value| !looks_like_low_signal_generated_copy(value))
    {
        return summary;
    }

    let mut candidates = session
        .preview
        .summary
        .iter()
        .filter_map(|entry| {
            let value = entry.value.trim();
            if value.is_empty()
                || entry.label == "Session"
                || entry.label == "Storage"
                || entry.label == "Started"
                || entry.label == "Updated"
                || entry.label == "UUID"
                || entry.label == "Target"
                || entry.label == "Prefix"
                || entry.label == "Host"
                || entry.label == "Deploy"
                || entry.label == "Bridge"
                || entry.label == "Messages"
            {
                None
            } else if entry.label == "Summary" {
                Some(value.to_string())
            } else {
                Some(format!("{}: {}", entry.label, value))
            }
        })
        .collect::<Vec<_>>();

    if candidates.is_empty() {
        for block in visible_preview_blocks(session).iter() {
            let joined = block
                .lines
                .iter()
                .map(|line| line.trim())
                .filter(|line| !line.is_empty())
                .filter(|line| {
                    let lower = line.to_ascii_lowercase();
                    !(lower.contains("/.yggterm/clipboard/")
                        || lower.contains("<collaboration_mode>")
                        || lower.contains("collaboration mode:")
                        || lower.contains("permissions instructions")
                        || lower.contains("how to request escalation")
                        || lower.contains("request_user_input"))
                })
                .take(2)
                .collect::<Vec<_>>()
                .join(" ");
            if !joined.is_empty() {
                candidates.push(joined);
            }
            if candidates.len() >= 2 {
                break;
            }
        }
    }

    if candidates.is_empty() {
        format!(
            "{} · {} messages · {} blocks",
            session.host_label,
            metadata_value(session, "Messages"),
            session.preview.blocks.len()
        )
    } else {
        candidates.into_iter().take(2).collect::<Vec<_>>().join(" ")
    }
}

fn terminal_session_still_active(shell: &ShellState, session_path: &str) -> bool {
    shell.server.active_view_mode() == WorkspaceViewMode::Terminal
        && shell.server.active_session_path() == Some(session_path)
}

fn terminal_precis(session: &ManagedSessionView) -> String {
    if let Some(summary) = preview_summary_metadata_value(session, "Summary")
        .filter(|value| !looks_like_low_signal_generated_copy(value))
    {
        return summary;
    }
    let mut candidates = Vec::new();
    for block in &session.preview.blocks {
        for line in &block.lines {
            let trimmed = line.trim();
            if !trimmed.is_empty() {
                candidates.push(trimmed.to_string());
            }
        }
    }
    for section in &session.rendered_sections {
        for line in &section.lines {
            let trimmed = line.trim();
            if !trimmed.is_empty() {
                candidates.push(trimmed.to_string());
            }
        }
    }
    candidates
        .into_iter()
        .find(|line| {
            !line.starts_with("Resume Codex session")
                && !line.starts_with("Open live terminal")
                && !line.starts_with("Preview mode renders")
                && !line.starts_with("GUI selection asks")
                && !line.starts_with("Launch command prepared")
        })
        .unwrap_or_else(|| session.status_line.clone())
}

fn is_remote_resume_agent_session(session: &ManagedSessionView) -> bool {
    session.session_path.starts_with("remote-session://")
        && session.source == SessionSource::LiveSsh
        && session.kind.is_agent()
}

#[component]
fn AgentModeSelector(
    selected: SessionKind,
    palette: Palette,
    disabled: bool,
    on_select: EventHandler<SessionKind>,
) -> Element {
    rsx! {
        div {
            style: toggle_slider_style(palette),
            button {
                style: toggle_slider_end_style(palette, selected == SessionKind::Codex),
                disabled: disabled,
                onclick: move |_| on_select.call(SessionKind::Codex),
                "Codex"
            }
            button {
                style: toggle_slider_end_style(palette, selected == SessionKind::CodexLiteLlm),
                disabled: disabled,
                onclick: move |_| on_select.call(SessionKind::CodexLiteLlm),
                "Codex LiteLLM"
            }
        }
    }
}

#[component]
fn PreviewRunBlock(
    session_id: String,
    run: PreviewRun,
    palette: Palette,
    on_toggle_block: EventHandler<usize>,
) -> Element {
    let user_run = run.tone == PreviewTone::User;
    let row_justify = if user_run { "flex-end" } else { "center" };
    let serif_stack = "\"Source Serif 4\", \"Noto Serif\", \"Iowan Old Style\", Georgia, serif";
    let column_style = if user_run {
        format!(
            "display:flex; flex-direction:column; gap:0; width:auto; max-width:min(72%, 720px); \
             min-width:0; box-sizing:border-box; font-family:{};",
            serif_stack
        )
    } else {
        format!(
            "display:flex; flex-direction:column; gap:0; width:min(100%, 740px); max-width:min(100%, 740px); min-width:0; \
             box-sizing:border-box; font-family:{};",
            serif_stack
        )
    };
    let dark = palette_is_dark(palette);
    let background = if user_run {
        if dark {
            "rgba(52,56,64,0.96)"
        } else {
            "rgba(241,243,246,0.98)"
        }
    } else {
        "transparent"
    };
    let border = if user_run {
        if dark {
            "rgba(96,104,116,0.32)"
        } else {
            "rgba(223,227,233,0.98)"
        }
    } else {
        "transparent"
    };
    let shadow = if user_run {
        if dark {
            "0 12px 24px rgba(0,0,0,0.18)"
        } else {
            "0 10px 20px rgba(148,163,184,0.10)"
        }
    } else {
        "none"
    };

    rsx! {
        div {
            style: format!("display:flex; justify-content:{}; width:100%; padding:0 8px; box-sizing:border-box;", row_justify),
            div {
                style: "{column_style}",
                div {
                    style: format!(
                        "display:flex; flex-direction:column; gap:0; background:{}; border-radius:{}px; \
                         box-shadow:{}; {} box-sizing:border-box; min-width:0; overflow:visible; {}",
                        background,
                        if user_run { 22 } else { 0 },
                        shadow,
                        if user_run {
                            format!("border:1px solid {};", border)
                        } else {
                            String::new()
                        },
                        if user_run {
                            String::new()
                        } else {
                            "border:none !important; outline:none !important; box-shadow:none !important; background:transparent !important;".to_string()
                        }
                    ),
                    for (entry_ix, entry) in run.entries.iter().cloned().enumerate() {
                        div {
                            key: "{entry.block_ix}",
                            id: "{preview_block_dom_id(&session_id, entry.block_ix)}",
                            "data-preview-entry": "1",
                            "data-preview-tone": if user_run { "user" } else { "assistant" },
                            "data-preview-block-ix": "{entry.block_ix}",
                            "data-preview-raw-timestamp": "{entry.block.timestamp}",
                            style: format!(
                                "width:100%; min-width:0; box-sizing:border-box; text-align:left; background:transparent; padding:{}; \
                                 {} {} {}",
                                if user_run { "13px 16px" } else { "12px 16px 14px 16px" },
                                if entry_ix > 0 {
                                    if user_run {
                                        if dark {
                                            "border-top:1px solid rgba(100,108,120,0.24);".to_string()
                                        } else {
                                            "border-top:1px solid rgba(223,227,233,0.92);".to_string()
                                        }
                                    } else {
                                        "border-top:none;".to_string()
                                    }
                                } else {
                                    String::new()
                                },
                                if user_run {
                                    "border-radius:0;".to_string()
                                } else {
                                    String::new()
                                },
                                if user_run {
                                    String::new()
                                } else {
                                    "border:none !important; outline:none !important; box-shadow:none !important; background:transparent !important;".to_string()
                                }
                            ),
                            div {
                                "data-preview-timestamp": "1",
                                style: "display:flex; align-items:center; justify-content:space-between; gap:12px; margin-bottom:8px;",
                                if !entry.display_timestamp.trim().is_empty() {
                                    div {
                                        style: format!("font-size:10px; color:{}; opacity:0.82;", palette.muted),
                                        "{entry.display_timestamp}"
                                    }
                                } else {
                                    div { style: "flex:1 1 auto;" }
                                }
                                if entry.block.folded || entry.block.lines.len() > 8 {
                                    button {
                                        style: format!(
                                            "border:none; background:transparent; color:{}; font-size:10px; opacity:0.72; padding:0;",
                                            palette.muted
                                        ),
                                        onclick: move |_| on_toggle_block.call(entry.block_ix),
                                        {if entry.block.folded { "Expand".to_string() } else { "Collapse".to_string() }}
                                    }
                                }
                            }
                            if entry.block.folded {
                                div {
                                    style: format!("font-size:11px; color:{};", palette.muted),
                                    "{entry.block.lines.len()} lines hidden"
                                }
                            } else {
                                PreviewContent { lines: entry.block.lines.clone(), palette }
                            }
                        }
                    }
                }
            }
        }
    }
}

