#[derive(Debug, Clone)]
struct TerminalTheme {
    background: String,
    foreground: String,
    cursor: String,
    font_size: f32,
    selection: String,
    black: String,
    red: String,
    green: String,
    yellow: String,
    blue: String,
    magenta: String,
    cyan: String,
    white: String,
    bright_black: String,
    bright_red: String,
    bright_green: String,
    bright_yellow: String,
    bright_blue: String,
    bright_magenta: String,
    bright_cyan: String,
    bright_white: String,
}

fn terminal_theme(
    ui_theme: UiTheme,
    _palette: Palette,
    font_size: f32,
    requested_name: &str,
) -> TerminalTheme {
    let fallback_name = if requested_name.trim().is_empty() {
        match ui_theme {
            UiTheme::ZedLight => "VS Code Light+",
            UiTheme::ZedDark => "Dark+",
        }
    } else {
        requested_name
    };
    if let Some(theme) = terminal_theme_by_name(fallback_name) {
        return TerminalTheme {
            background: theme.palette.background.clone(),
            foreground: theme.palette.foreground.clone(),
            cursor: theme.palette.cursor.clone(),
            font_size: font_size.max(5.0),
            selection: theme.palette.selection.clone(),
            black: theme.palette.black.clone(),
            red: theme.palette.red.clone(),
            green: theme.palette.green.clone(),
            yellow: theme.palette.yellow.clone(),
            blue: theme.palette.blue.clone(),
            magenta: theme.palette.magenta.clone(),
            cyan: theme.palette.cyan.clone(),
            white: theme.palette.white.clone(),
            bright_black: theme.palette.bright_black.clone(),
            bright_red: theme.palette.bright_red.clone(),
            bright_green: theme.palette.bright_green.clone(),
            bright_yellow: theme.palette.bright_yellow.clone(),
            bright_blue: theme.palette.bright_blue.clone(),
            bright_magenta: theme.palette.bright_magenta.clone(),
            bright_cyan: theme.palette.bright_cyan.clone(),
            bright_white: theme.palette.bright_white.clone(),
        };
    }
    TerminalTheme {
        background: "#f7f8fa".to_string(),
        foreground: "#1f2328".to_string(),
        cursor: "#005fb8".to_string(),
        font_size: font_size.max(5.0),
        selection: "rgba(9, 105, 218, 0.20)".to_string(),
        black: "#24292f".to_string(),
        red: "#cd3131".to_string(),
        green: "#00bc00".to_string(),
        yellow: "#949800".to_string(),
        blue: "#0451a5".to_string(),
        magenta: "#bc05bc".to_string(),
        cyan: "#0598bc".to_string(),
        white: "#57606a".to_string(),
        bright_black: "#6e7781".to_string(),
        bright_red: "#cd3131".to_string(),
        bright_green: "#14ce14".to_string(),
        bright_yellow: "#b5ba00".to_string(),
        bright_blue: "#0451a5".to_string(),
        bright_magenta: "#bc05bc".to_string(),
        bright_cyan: "#0598bc".to_string(),
        bright_white: "#8c959f".to_string(),
    }
}

fn terminal_placeholder_text(session: &ManagedSessionView) -> Option<String> {
    if !session.session_path.starts_with("remote-session://") {
        return None;
    }
    if let Some(prefill) = remote_resume_terminal_prefill(session) {
        return Some(prefill);
    }
    let mut lines = vec!["Resuming live Codex session...".to_string()];
    if !session.host_label.trim().is_empty() {
        lines.push(format!("Host: {}", session.host_label.trim()));
    }
    let cwd = metadata_value(session, "Cwd");
    if !cwd.trim().is_empty() {
        lines.push(format!("Workspace: {}", cwd.trim()));
    }
    match session.remote_deploy_state {
        RemoteDeployState::NotRequired => {}
        RemoteDeployState::Planned => lines.push("Deploy: planned".to_string()),
        RemoteDeployState::CopyingBinary => lines.push("Deploy: copying yggterm".to_string()),
        RemoteDeployState::Ready => lines.push("Deploy: ready".to_string()),
    }
    lines.push("Waiting for the remote terminal to paint...".to_string());
    Some(format!("{}\r\n", lines.join("\r\n")))
}

fn remote_resume_terminal_prefill(session: &ManagedSessionView) -> Option<String> {
    let blocks = remote_resume_overlay_blocks(session);
    if blocks.is_empty() {
        let summary = terminal_precis(session);
        let summary = summary.trim();
        if summary.is_empty() {
            return None;
        }
        return Some(format!(
            "Saved transcript · {} · typing takes over the live terminal\r\n\r\n{}\r\n",
            session.host_label, summary
        ));
    }
    let mut lines = vec![format!(
        "Saved transcript · {} · typing takes over the live terminal",
        session.host_label
    )];
    lines.push(String::new());
    for block in blocks {
        let heading = if block.timestamp.is_empty() {
            if block.user {
                "USER".to_string()
            } else {
                "ASSISTANT".to_string()
            }
        } else if block.user {
            format!("USER · {}", block.timestamp)
        } else {
            format!("ASSISTANT · {}", block.timestamp)
        };
        lines.push(heading);
        for line in block.text.lines() {
            let trimmed = line.trim();
            if !trimmed.is_empty() {
                lines.push(trimmed.to_string());
            }
        }
        lines.push(String::new());
    }
    Some(format!("{}\r\n", lines.join("\r\n")))
}

fn xterm_assets_bootstrap_script() -> String {
    let css = serde_json::to_string(XTERM_CSS).expect("serialize xterm css");
    let xterm = serde_json::to_string(XTERM_JS).expect("serialize xterm js");
    let fit = serde_json::to_string(XTERM_FIT_JS).expect("serialize xterm fit addon");
    format!(
        r#"
        (() => {{
          window.__yggtermXtermBootstrapError = null;
          const styleId = "yggterm-xterm-style";
          if (!document.getElementById(styleId)) {{
            const style = document.createElement("style");
            style.id = styleId;
            style.textContent = {css};
            document.head.appendChild(style);
          }}
          const injectScript = (id, source) => {{
            if (document.getElementById(id)) {{
              return;
            }}
            const script = document.createElement("script");
            script.id = id;
            script.type = "text/javascript";
            script.text = source;
            document.head.appendChild(script);
          }};
          try {{
            if (!window.Terminal) {{
              injectScript("yggterm-xterm-script", {xterm});
            }}
            if (!window.FitAddon || !window.FitAddon.FitAddon) {{
              injectScript("yggterm-xterm-fit-script", {fit});
            }}
          }} catch (error) {{
            window.__yggtermXtermBootstrapError = error && error.message ? error.message : String(error);
          }}
        }})();
        "#
    )
}

fn terminal_host_id(session_path: &str) -> String {
    let mut id = String::from("yggterm-terminal-");
    for ch in session_path.chars() {
        if ch.is_ascii_alphanumeric() {
            id.push(ch.to_ascii_lowercase());
        } else {
            id.push('-');
        }
    }
    id
}

fn terminal_mount_host_id(session_path: &str, mount_epoch: u64) -> String {
    format!("{}-m{}", terminal_host_id(session_path), mount_epoch)
}

fn sidebar_row_dom_id(path: &str) -> String {
    let mut id = String::from("yggterm-sidebar-row-");
    for ch in path.chars() {
        if ch.is_ascii_alphanumeric() {
            id.push(ch.to_ascii_lowercase());
        } else {
            id.push('-');
        }
    }
    id
}

fn terminal_instance_key(session_path: &str, font_size: f32) -> String {
    format!("{session_path}-{font_size:.1}")
}

fn current_millis() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|duration| duration.as_millis() as u64)
        .unwrap_or(0)
}

fn notification_delivery_mode(settings: &AppSettings) -> NotificationDeliveryMode {
    match (settings.in_app_notifications, settings.system_notifications) {
        (true, true) => NotificationDeliveryMode::Both,
        (false, true) => NotificationDeliveryMode::System,
        _ => NotificationDeliveryMode::InApp,
    }
}

fn apply_notification_delivery_mode(settings: &mut AppSettings, mode: NotificationDeliveryMode) {
    match mode {
        NotificationDeliveryMode::InApp => {
            settings.in_app_notifications = true;
            settings.system_notifications = false;
        }
        NotificationDeliveryMode::Both => {
            settings.in_app_notifications = true;
            settings.system_notifications = true;
        }
        NotificationDeliveryMode::System => {
            settings.in_app_notifications = false;
            settings.system_notifications = true;
        }
    }
}

fn emit_notification_chime() {
    let _ = document::eval(
        r#"
        (() => {
          try {
            const ctx = new (window.AudioContext || window.webkitAudioContext)();
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();
            osc.type = "sine";
            osc.frequency.value = 880;
            gain.gain.value = 0.03;
            osc.connect(gain);
            gain.connect(ctx.destination);
            osc.start();
            setTimeout(() => {
              try { osc.stop(); } catch (_error) {}
              try { ctx.close(); } catch (_error) {}
            }, 85);
          } catch (_error) {}
        })();
        "#,
    );
}

fn emit_system_notification(title: &str, message: &str) {
    let _ = send_user_notification(title, message);
}

fn apply_active_terminal_zoom(state: Signal<ShellState>) {
    let snapshot = state.read().snapshot();
    if snapshot.active_view_mode != WorkspaceViewMode::Terminal {
        return;
    }
    let Some(session) = snapshot.active_session else {
        return;
    };
    let theme = terminal_theme(
        snapshot.settings.theme,
        snapshot.palette,
        snapshot.settings.terminal_font_size,
        &snapshot.settings.terminal_theme_name,
    );
    info!(
        session=%session.session_path,
        font_size=theme.font_size,
        "applying live terminal zoom"
    );
    let _ = document::eval(&terminal_apply_script_for_session(
        &session.session_path,
        &theme,
    ));
}

fn terminal_eval_script(host_id: &str, theme: &TerminalTheme) -> String {
    let css = serde_json::to_string(XTERM_CSS).expect("serialize xterm css");
    let xterm = serde_json::to_string(XTERM_JS).expect("serialize xterm js");
    let fit_bundle = serde_json::to_string(XTERM_FIT_JS).expect("serialize xterm fit addon");
    let background =
        serde_json::to_string(&theme.background).expect("serialize terminal background");
    let foreground =
        serde_json::to_string(&theme.foreground).expect("serialize terminal foreground");
    let cursor = serde_json::to_string(&theme.cursor).expect("serialize terminal cursor");
    let selection = serde_json::to_string(&theme.selection).expect("serialize terminal selection");
    let black = serde_json::to_string(&theme.black).expect("serialize terminal black");
    let red = serde_json::to_string(&theme.red).expect("serialize terminal red");
    let green = serde_json::to_string(&theme.green).expect("serialize terminal green");
    let yellow = serde_json::to_string(&theme.yellow).expect("serialize terminal yellow");
    let blue = serde_json::to_string(&theme.blue).expect("serialize terminal blue");
    let magenta = serde_json::to_string(&theme.magenta).expect("serialize terminal magenta");
    let cyan = serde_json::to_string(&theme.cyan).expect("serialize terminal cyan");
    let white = serde_json::to_string(&theme.white).expect("serialize terminal white");
    let bright_black =
        serde_json::to_string(&theme.bright_black).expect("serialize terminal bright black");
    let bright_red =
        serde_json::to_string(&theme.bright_red).expect("serialize terminal bright red");
    let bright_green =
        serde_json::to_string(&theme.bright_green).expect("serialize terminal bright green");
    let bright_yellow =
        serde_json::to_string(&theme.bright_yellow).expect("serialize terminal bright yellow");
    let bright_blue =
        serde_json::to_string(&theme.bright_blue).expect("serialize terminal bright blue");
    let bright_magenta =
        serde_json::to_string(&theme.bright_magenta).expect("serialize terminal bright magenta");
    let bright_cyan =
        serde_json::to_string(&theme.bright_cyan).expect("serialize terminal bright cyan");
    let bright_white =
        serde_json::to_string(&theme.bright_white).expect("serialize terminal bright white");
    let constructed_debug = if cfg!(debug_assertions) {
        "dioxus.send({ kind: \"debug\", message: `constructed host=${hostId} fontSize=${term.options.fontSize} cols=${term.cols} rows=${term.rows}` });"
    } else {
        ""
    };
    let reset_debug = if cfg!(debug_assertions) {
        "dioxus.send({ kind: \"debug\", message: `reset host=${hostId} fontSize=${term.options.fontSize}` });"
    } else {
        ""
    };
    format!(
        r#"
        const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
        const hostId = {host_id:?};
        let host = document.getElementById(hostId);
        dioxus.send({{ kind: "debug", message: `bootstrap host=${{hostId}} present=${{!!host}}` }});
        if (!host) {{
            for (let attempt = 0; attempt < 80; attempt += 1) {{
                await sleep(25);
                host = document.getElementById(hostId);
                if (host) {{
                    dioxus.send({{
                        kind: "debug",
                        message: `bootstrap host=${{hostId}} mounted on retry=${{attempt + 1}}`
                    }});
                    break;
                }}
            }}
        }}
        if (!host) {{
            dioxus.send({{ kind: "debug", message: `bootstrap host missing for ${{hostId}} after retries` }});
            dioxus.send({{ kind: "ready" }});
            return;
        }}
        const ensureXtermAssets = async () => {{
            window.__yggtermXtermBootstrapError = null;
            const styleId = "yggterm-xterm-style";
            if (!document.getElementById(styleId)) {{
                const style = document.createElement("style");
                style.id = styleId;
                style.textContent = {css};
                document.head.appendChild(style);
            }}
            const injectScript = (id, source) => {{
                if (document.getElementById(id)) {{
                    return;
                }}
                const script = document.createElement("script");
                script.id = id;
                script.type = "text/javascript";
                script.text = source;
                document.head.appendChild(script);
            }};
            try {{
                if (!window.Terminal) {{
                    injectScript("yggterm-xterm-script", {xterm});
                }}
                if (!window.FitAddon || !window.FitAddon.FitAddon) {{
                    injectScript("yggterm-xterm-fit-script", {fit_bundle});
                }}
                for (let attempt = 0; attempt < 80; attempt += 1) {{
                    if (window.Terminal && window.FitAddon && window.FitAddon.FitAddon) {{
                        return true;
                    }}
                    await sleep(50);
                }}
                return false;
            }} catch (error) {{
                window.__yggtermXtermBootstrapError = error && error.message ? error.message : String(error);
                return false;
            }}
        }};
        const assetsReady = await ensureXtermAssets();
        dioxus.send({{
            kind: "debug",
            message: `assets host=${{hostId}} ready=${{assetsReady}} terminal=${{!!window.Terminal}} fit=${{!!(window.FitAddon && window.FitAddon.FitAddon)}} bootstrap=${{window.__yggtermXtermBootstrapError || "none"}}`
        }});
        if (!assetsReady || !window.Terminal || !window.FitAddon || !window.FitAddon.FitAddon) {{
            const details = [
              window.Terminal ? "Terminal:ok" : "Terminal:missing",
              window.FitAddon && window.FitAddon.FitAddon ? "FitAddon:ok" : "FitAddon:missing",
              window.__yggtermXtermBootstrapError ? `Bootstrap:${{window.__yggtermXtermBootstrapError}}` : "Bootstrap:none",
            ].join(" · ");
            host.innerHTML = `<div style="padding:18px;color:#fca5a5;font:13px system-ui;">xterm.js assets failed to load.<br><span style="opacity:0.75">${{details}}</span></div>`;
            dioxus.send({{ kind: "debug", message: details }});
            dioxus.send({{ kind: "ready" }});
            while (true) {{
                await dioxus.recv();
            }}
        }}
        if (window.__yggtermXtermCleanup) {{
            try {{
                window.__yggtermXtermCleanup();
            }} catch (_error) {{}}
        }}
        host.innerHTML = "";
        const term = new window.Terminal({{
            allowTransparency: false,
            convertEol: true,
            cursorBlink: true,
            fontFamily: "'JetBrains Mono', 'Iosevka Term', 'Fira Code', monospace",
            fontSize: {font_size},
            fontWeight: "500",
            fontWeightBold: "700",
            minimumContrastRatio: 6,
            scrollback: 5000,
            theme: {{
                background: {background},
                foreground: {foreground},
                cursor: {cursor},
                selectionBackground: {selection},
                black: {black},
                red: {red},
                green: {green},
                yellow: {yellow},
                blue: {blue},
                magenta: {magenta},
                cyan: {cyan},
                white: {white},
                brightBlack: {bright_black},
                brightRed: {bright_red},
                brightGreen: {bright_green},
                brightYellow: {bright_yellow},
                brightBlue: {bright_blue},
                brightMagenta: {bright_magenta},
                brightCyan: {bright_cyan},
                brightWhite: {bright_white},
            }},
        }});
        const fitAddon = new window.FitAddon.FitAddon();
        term.loadAddon(fitAddon);
        term.open(host);
        const handleWheel = (event) => {{
            if (!event || !Number.isFinite(event.deltaY) || event.deltaY === 0) {{
                return;
            }}
            const deltaLines = Math.max(1, Math.round(Math.abs(event.deltaY) / 40));
            term.scrollLines(event.deltaY > 0 ? deltaLines : -deltaLines);
            event.preventDefault();
            event.stopPropagation();
        }};
        host.addEventListener("wheel", handleWheel, {{ passive: false }});
        term.attachCustomKeyEventHandler((event) => {{
            const accel = event.ctrlKey || event.metaKey;
            const key = (event.key || '').toLowerCase();
            if (!accel) {{
                return true;
            }}
            if (!event.shiftKey && key === 'v') {{
                dioxus.send({{ kind: "clipboard_image_request" }});
                return false;
            }}
            if (!event.shiftKey || (key !== 'c' && key !== 'x')) {{
                return true;
            }}
            const selection = term.getSelection ? term.getSelection() : "";
            if (!selection) {{
                dioxus.send({{
                    kind: "clipboard_error",
                    action: key === 'x' ? "cut" : "copy",
                    message: "Select terminal text before using the clipboard shortcut.",
                }});
                return false;
            }}
            const action = key === 'x' ? "cut" : "copy";
            const finish = () => {{
                try {{
                    if (action === "cut" && term.clearSelection) {{
                        term.clearSelection();
                    }}
                }} catch (_error) {{}}
                dioxus.send({{ kind: "clipboard", action, chars: selection.length }});
            }};
            const fail = (error) => {{
                dioxus.send({{
                    kind: "clipboard_error",
                    action,
                    message: error && error.message ? error.message : "Clipboard access was denied.",
                }});
            }};
            try {{
                if (navigator.clipboard && navigator.clipboard.writeText) {{
                    navigator.clipboard.writeText(selection).then(finish).catch(fail);
                }} else {{
                    fail(new Error("Clipboard API is unavailable."));
                }}
            }} catch (error) {{
                fail(error);
            }}
            return false;
        }});
        window.__yggtermXtermHosts = window.__yggtermXtermHosts || {{}};
        window.__yggtermXtermHosts[hostId] = {{
            term,
            fitAddon,
            hostId,
            sessionPath: host.getAttribute("data-terminal-session-path") || "",
            mountedAt: Date.now(),
        }};
        dioxus.send({{
            kind: "debug",
            message: `constructed host=${{hostId}} cols=${{term.cols}} rows=${{term.rows}}`
        }});
        const emitResize = () => {{
            try {{
                fitAddon.fit();
                dioxus.send({{ kind: "resize", cols: term.cols, rows: term.rows }});
            }} catch (_error) {{}}
        }};
        const scheduleResizeNudges = () => {{
            [180, 700].forEach((delayMs) => {{
                window.setTimeout(() => {{
                    emitResize();
                }}, delayMs);
            }});
        }};
        const resizeObserver = new ResizeObserver(() => emitResize());
        resizeObserver.observe(host);
        term.onData((data) => dioxus.send({{ kind: "input", data }}));
        window.__yggtermXtermCleanup = () => {{
            try {{
                resizeObserver.disconnect();
            }} catch (_error) {{}}
            try {{
                host.removeEventListener("wheel", handleWheel);
            }} catch (_error) {{}}
            try {{
                term.dispose();
            }} catch (_error) {{}}
            try {{
                if (window.__yggtermXtermHosts) {{
                    delete window.__yggtermXtermHosts[hostId];
                }}
            }} catch (_error) {{}}
            host.innerHTML = "";
        }};
        emitResize();
        scheduleResizeNudges();
        {constructed_debug}
        dioxus.send({{ kind: "ready" }});
        while (true) {{
            const message = await dioxus.recv();
            if (!message) {{
                continue;
            }}
            if (message.kind === "reset") {{
                term.clear();
                term.options.fontSize = message.font_size;
                term.options.theme = {{
                    background: message.background,
                    foreground: message.foreground,
                    cursor: message.cursor,
                    selectionBackground: message.selection,
                    black: message.black,
                    red: message.red,
                    green: message.green,
                    yellow: message.yellow,
                    blue: message.blue,
                    magenta: message.magenta,
                    cyan: message.cyan,
                    white: message.white,
                    brightBlack: message.bright_black,
                    brightRed: message.bright_red,
                    brightGreen: message.bright_green,
                    brightYellow: message.bright_yellow,
                    brightBlue: message.bright_blue,
                    brightMagenta: message.bright_magenta,
                    brightCyan: message.bright_cyan,
                    brightWhite: message.bright_white,
                }};
                {reset_debug}
                requestAnimationFrame(() => emitResize());
                scheduleResizeNudges();
            }} else if (message.kind === "write") {{
                term.write(message.data);
            }}
        }}
        "#,
        font_size = theme.font_size,
        background = background,
        foreground = foreground,
        cursor = cursor,
        selection = selection,
        black = black,
        red = red,
        green = green,
        yellow = yellow,
        blue = blue,
        magenta = magenta,
        cyan = cyan,
        white = white,
        bright_black = bright_black,
        bright_red = bright_red,
        bright_green = bright_green,
        bright_yellow = bright_yellow,
        bright_blue = bright_blue,
        bright_magenta = bright_magenta,
        bright_cyan = bright_cyan,
        bright_white = bright_white,
        constructed_debug = constructed_debug,
        reset_debug = reset_debug
    )
}

