fn shell_backdrop_style(maximized: bool) -> &'static str {
    if maximized || linux_kde_wayland_safe_mode() {
        "none"
    } else {
        "blur(10px) saturate(135%)"
    }
}

fn linux_kde_wayland_safe_mode() -> bool {
    #[cfg(target_os = "linux")]
    {
        std::env::var_os("WAYLAND_DISPLAY").is_some()
            && std::env::var("XDG_CURRENT_DESKTOP")
                .map(|value| value.to_ascii_lowercase().contains("kde"))
                .unwrap_or(false)
    }
    #[cfg(not(target_os = "linux"))]
    {
        false
    }
}

fn overlay_backdrop_style(default_style: &'static str) -> &'static str {
    if linux_kde_wayland_safe_mode() {
        "none"
    } else {
        default_style
    }
}

fn shell_style(
    palette: Palette,
    radius: u8,
    shell_tint: &str,
    shell_gradient: &str,
    maximized: bool,
) -> String {
    let backdrop = shell_backdrop_style(maximized);
    let frame_inset = if maximized { 0.0 } else { SHELL_FRAME_INSET_PX };
    let frame_outline = if maximized {
        "none".to_string()
    } else {
        "inset 0 0 0 1px rgba(214,222,232,0.72)".to_string()
    };
    let box_shadow = if frame_outline == "none" {
        palette.shadow.to_string()
    } else {
        format!("{}, {}", palette.shadow, frame_outline)
    };
    format!(
        "position:absolute; inset:{}px; display:flex; flex-direction:column; overflow:hidden; \
         border-radius:{}px; background-color:{}; background-image:{}; box-shadow:{}; backdrop-filter:{}; \
         -webkit-backdrop-filter:{}; font-family:{};",
        frame_inset,
        radius,
        shell_tint,
        shell_gradient,
        box_shadow,
        backdrop,
        backdrop,
        interface_font_family()
    )
}

fn sync_window_frame_state(shell: &mut ShellState) {
    shell.maximized = window().is_maximized();
}

